code = """import json
import re

file_path = locals()['var_function-call-5206058778469443849']
with open(file_path, 'r') as f:
    businesses = json.load(f)

category_businesses = {}

patterns = [
    r"category of '(.*)'",
    r"categories of (.*)",
    r"products in the fields of (.*)",
    r"services, including (.*)",
    r"services including (.*)",
    r"services in (.*)",
    r"destination for (.*)"
]

for b in businesses:
    desc = b.get('description', '')
    bid = b.get('business_id')
    
    categories_str = None
    for p in patterns:
        match = re.search(p, desc)
        if match:
            categories_str = match.group(1)
            break
    
    if categories_str:
        if categories_str.endswith('.'):
            categories_str = categories_str[:-1]
        cats = categories_str.split(',')
        clean_cats = []
        for i, c in enumerate(cats):
            c = c.strip()
            if i == len(cats) - 1 and c.startswith('and '):
                c = c[4:]
            c = c.replace("'", "")
            if c:
                clean_cats.append(c)
        
        for c in clean_cats:
            if c not in category_businesses:
                category_businesses[c] = []
            category_businesses[c].append(bid)

ids_shopping = category_businesses.get("Shopping", [])
converted_ids_shopping = [bid.replace("businessid_", "businessref_") for bid in ids_shopping]

print("__RESULT__:")
print(json.dumps({"category": "Shopping", "ids": converted_ids_shopping}))"""

